# coding:utf-8


def main():
    n, a, b = map(int, input().split())
    s = input()
    ans = 0
    # 计算最优值
    if a == 0:
        ans = b
    elif b == 0:
        ans = a
    else:
        # 计算前后缀
        # 前缀：计算在最优解中，可以被安排到前面的学生数量
        # 后缀：计算在最优解中，可以被安排到后面的学生数量
        pre = [0] * n
        suf = [0] * n
        # 计算前缀
        for i in range(n):
            if s[i] == '*':
                pre[i] = 1
            else:
                pre[i] = 0
            if i > 0:
                pre[i] += pre[i - 1]
        # 计算后缀
        for i in range(n - 1, -1, -1):
            if s[i] == '*':
                suf[i] = 1
            else:
                suf[i] = 0
            if i < n - 1:
                suf[i] += suf[i + 1]
        # 计算答案
        ans = min(a, b)
        for i in range(n - 1):
            # 计算前缀和后缀的最小值
            ans = min(ans, min(pre[i], suf[i + 1]))
    print(ans)


if __name__ == '__main__':
    main()
